def validate_redirect_uri(redirect_uri):
    """Validate that redirect_uri matches configured domain"""
    if not redirect_uri:
        return False
    
    parsed_uri = urlparse(redirect_uri)
    if not parsed_uri.scheme or not parsed_uri.netloc:
        return False
    
    # Check if domain is contained in redirect_uri (supports subdomains)
    return DOMAIN in redirect_uri

